import{c as a,Q as n,j as t,m as s}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"HavenBot — conversations & confirmations","description":"How chat, ConfirmModal, and signing fit together.","frontmatter":{"title":"HavenBot — conversations & confirmations","description":"How chat, ConfirmModal, and signing fit together."},"headers":[],"relativePath":"havenbot/conversations.md","filePath":"havenbot/conversations.md","lastUpdated":1780245214000}'),o={name:"havenbot/conversations.md"};function i(r,e,l,p,d,c){return n(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="conversations-confirmations" tabindex="-1">Conversations &amp; confirmations <a class="header-anchor" href="#conversations-confirmations" aria-label="Permalink to &quot;Conversations &amp; confirmations&quot;">​</a></h1><p>HavenBot&#39;s conversation surface is <strong>streaming chat</strong> plus a per-action <strong>ConfirmModal</strong>. This page covers the round-trip from your message to a settled on-chain action.</p><h2 id="the-full-round-trip" tabindex="-1">The full round-trip <a class="header-anchor" href="#the-full-round-trip" aria-label="Permalink to &quot;The full round-trip&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. You type a message.</span></span>
<span class="line"><span>2. Frontend opens a POST to /api/v1/agent/chat/stream (SSE).</span></span>
<span class="line"><span>3. Backend builds the LLM context (tier, recent audit, tool catalog).</span></span>
<span class="line"><span>4. LLM (Gemini) streams text and may emit a tool_call.</span></span>
<span class="line"><span>5. For each tool_call:</span></span>
<span class="line"><span>   a. Backend dispatches to the tool&#39;s use-case (read or propose).</span></span>
<span class="line"><span>   b. Read tools return data; the LLM streams a textual answer.</span></span>
<span class="line"><span>   c. Propose tools return an ActionDescriptor; the frontend opens ConfirmModal.</span></span>
<span class="line"><span>6. You confirm in ConfirmModal:</span></span>
<span class="line"><span>   a. Your MuHaven wallet + session key signs the UserOp.</span></span>
<span class="line"><span>   b. ZeroDev bundler relays.</span></span>
<span class="line"><span>   c. Settlement settles on Arb Sepolia.</span></span>
<span class="line"><span>7. Frontend POSTs /api/v1/agent/tools/commit with the action hash.</span></span>
<span class="line"><span>8. Backend writes the audit row.</span></span>
<span class="line"><span>9. HavenBot replies with a confirmation line in chat.</span></span></code></pre></div><p>The two wire shapes that matter:</p><ul><li><strong>Read</strong> — tool_call → data → LLM textual answer. No signing.</li><li><strong>Propose</strong> — tool_call → ActionDescriptor → ConfirmModal → user-driven sign → commit → audit.</li></ul><h2 id="streaming-behavior" tabindex="-1">Streaming behavior <a class="header-anchor" href="#streaming-behavior" aria-label="Permalink to &quot;Streaming behavior&quot;">​</a></h2><p>Replies tokenize live. You&#39;ll see:</p><ul><li>A typing indicator the moment you submit.</li><li>Text streamed token-by-token (typically 30-80 tokens/sec).</li><li>Tool widgets (portfolio card, quote box) rendered in-line once the tool call resolves.</li><li>The ConfirmModal opening (if applicable) right after the tool result returns.</li></ul><p>You can interrupt at any point with the <strong>Stop</strong> button. The backend cancels the upstream LLM stream; partial tool calls are discarded. No state changes on interrupt.</p><h2 id="the-confirmmodal" tabindex="-1">The ConfirmModal <a class="header-anchor" href="#the-confirmmodal" aria-label="Permalink to &quot;The ConfirmModal&quot;">​</a></h2><p>Every state-mutating action opens a ConfirmModal. The modal renders:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  ✦ Buy 50.00 mhUSDC of &lt;TOKEN&gt;                       │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  You&#39;re spending      50.00 mhUSDC                   │</span></span>
<span class="line"><span>│  You&#39;ll receive       ~49.85 &lt;TOKEN&gt; (encrypted)     │</span></span>
<span class="line"><span>│  Current NAV          $1.003                         │</span></span>
<span class="line"><span>│  Slippage             0.30% max                      │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  ──────────────────────────────────────────────      │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  Signing as           0x1234…cdef                    │</span></span>
<span class="line"><span>│  Session key TTL      52 minutes remaining           │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  [Cancel]                              [Confirm]     │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────┘</span></span></code></pre></div><p>Two terminal states:</p><ol><li><strong>Success</strong> — toast &quot;Settled&quot; + Arbiscan link. Modal closes.</li><li><strong>Error</strong> — toast with the revert reason. Audit log records a <code>PermitAttempted</code> row (failed-attempt forensic).</li></ol><h2 id="signing-—-passkey-vs-session-key" tabindex="-1">Signing — passkey vs session key <a class="header-anchor" href="#signing-—-passkey-vs-session-key" aria-label="Permalink to &quot;Signing — passkey vs session key&quot;">​</a></h2><p>Your MuHaven wallet has two signers:</p><ol><li><strong>Master passkey</strong> — your WebAuthn credential. Used at sign-in, for MuHaven wallet rebind, and for high-stakes confirmations.</li><li><strong>Session key</strong> — a short-lived (default 1h) ECDSA key with <strong>narrow scope</strong> (only MuHaven functions, only your wallet, only for the session). Installed by your passkey at sign-in; uninstalled by <code>/pause</code>.</li></ol><p>In Advisory tier, every action prompts your passkey. In Confirm-per-action tier, the session key signs without re-prompting the passkey for the session duration (you still confirm each action). In <strong>Scoped autonomy</strong> — the live autonomous tier — a bounded session key held by the broker daemon signs the agent&#39;s buys, sells, and claims without prompting you, up to a per-trade cap and until the TTL expires. <strong>Policy-bound</strong> is a designed automation tier whose encrypted-threshold auto-signing cron is built but disabled in every deployment, so it does not auto-sign today.</p><p>See <a href="/policy/session-keys">Session keys</a> for the full scope spec.</p><h2 id="read-tool-widgets" tabindex="-1">Read-tool widgets <a class="header-anchor" href="#read-tool-widgets" aria-label="Permalink to &quot;Read-tool widgets&quot;">​</a></h2><p>Some tool results render as in-line widgets instead of raw text:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Widget</th></tr></thead><tbody><tr><td><code>muhaven_portfolio_summary</code></td><td>Portfolio card with token list, signal flags, &quot;balanced/overexposed&quot; pill</td></tr><tr><td><code>muhaven_quote</code></td><td>Quote box with NAV, slippage, estimated shares</td></tr><tr><td><code>muhaven_unseal_position</code></td><td>Cleartext balance bubble (decrypted client-side via permit)</td></tr><tr><td><code>muhaven_audit_query</code></td><td>Compact audit table, last 10 rows + pagination</td></tr></tbody></table><p>Widget rendering is opt-in per tool — the LLM can also produce a textual answer if the widget surface is wrong for the question.</p><h2 id="chat-history" tabindex="-1">Chat history <a class="header-anchor" href="#chat-history" aria-label="Permalink to &quot;Chat history&quot;">​</a></h2><p>Your chat history is <strong>server-managed</strong>:</p><ul><li>Stored against your user ID on the MuHaven backend.</li><li>Pulled into the LLM context for follow-up turns within the same session.</li><li>Cleared by <code>/agent → ⋯ menu → Clear chat</code>.</li></ul><div class="warning custom-block"><p class="custom-block-title">Don&#39;t paste secrets in chat</p><p>The chat history is plaintext on the backend. Never paste a private key, an API token, or any cleartext encrypted-balance value into the chat. (HavenBot has no use for them and the policy gate doesn&#39;t accept them anyway.)</p></div><h2 id="multi-turn-behavior" tabindex="-1">Multi-turn behavior <a class="header-anchor" href="#multi-turn-behavior" aria-label="Permalink to &quot;Multi-turn behavior&quot;">​</a></h2><p>The current chat loop is <strong>single-turn</strong>: text → tool_call → tool_result → done. If you want a follow-up reasoning step (&quot;now that you&#39;ve shown me the portfolio, recommend a buy&quot;), send a second message.</p><h2 id="what-havenbot-won-t-do" tabindex="-1">What HavenBot won&#39;t do <a class="header-anchor" href="#what-havenbot-won-t-do" aria-label="Permalink to &quot;What HavenBot won&#39;t do&quot;">​</a></h2><ul><li><strong>Sign without showing you the preview in an interactive session.</strong> Every interactive action opens the ConfirmModal. (Scoped autonomy is the exception by design: once you&#39;ve armed a bounded session key with a per-trade cap + TTL, the broker daemon signs buys/sells/claims within those bounds without a per-action prompt — that&#39;s the whole point of the autonomous tier.)</li><li><strong>Submit a tool call that the policy gate rejected.</strong> A jailbreak that fabricates &quot;approved&quot; in the LLM response cannot bypass the deterministic gate.</li><li><strong>Decrypt your balance server-side.</strong> All <code>decryptForView</code> calls run in your browser with your local permit.</li><li><strong>Hold your private key.</strong> The MuHaven wallet + session key are signers; the LLM is not.</li></ul><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/havenbot/investor-playbook">Investor playbook</a> — phrasing that works.</li><li><a href="/havenbot/issuer-playbook">Issuer playbook</a> — distribute yield, KYC churn, unpause.</li><li><a href="/policy/tiered-autonomy">Tiered autonomy</a> — how Advisory / Confirm / Policy-bound / Scoped autonomy interact with ConfirmModal.</li></ul>`,34)])])}const m=a(o,[["render",i]]);export{u as __pageData,m as default};
